342→export default function FloorplanWorkspace({ initialProject, isPlayground = false }) {
343→  return (
344→    <div className="editorRoot">
345→      <ProjectProvider initialProject={initialProject}>
346→        <ClipboardProvider>
347→          <FloorplanInner isPlayground={isPlayground} />
348→        </ClipboardProvider>
349→      </ProjectProvider>
350→    </div>
351→  );
352→}
