 77→export default function Sidebar() {
 78→  const { project, dispatch, duplicateFloor } = useProject();
 79→  const { activeFloorId, activeSheetId, selectedId, selectedType, workspaceMode, modelTarget, activePhaseId, phaseViewMode, dispatch: editorDispatch } = useEditor();
