 92→    roofPlanes: false,
 93→    ridges: false,
 94→    valleys: false,
 95→    hips: false,
 96→    parapets: false,
 97→    drains: false,
 98→    roofOpenings: false,
 99→    trusses: false,
100→    sheets: false,
101→    phases: false,
102→    slabs: false,
103→    walls: false,
104→    annotations: false,
105→    beams: false,
106→    stairs: false,
107→    landings: false,
108→    doors: false,
109→    windows: false,
110→    columns: false,
111→    rooms: false,
112→  });
113→
114→  const selectObject = (id, type) => {
115→    editorDispatch({ type: 'SELECT_OBJECT', id, objectType: type });
116→  };
117→
118→  const selectFloor = (floorId) => {
119→    editorDispatch({ type: 'SET_MODEL_TARGET', modelTarget: 'floor' });
120→    editorDispatch({ type: 'SET_ACTIVE_FLOOR', floorId });
121→    editorDispatch({ type: 'SELECT_OBJECT', id: floorId, objectType: 'floor' });
122→  };
123→
124→  const selectRoofObject = (id, type) => {
125→    editorDispatch({ type: 'SET_MODEL_TARGET', modelTarget: 'roof' });
126→    editorDispatch({ type: 'SELECT_OBJECT', id, objectType: type });
127→  };
128→
129→  const openRoofWorkspace = () => {
130→    editorDispatch({ type: 'SET_MODEL_TARGET', modelTarget: 'roof' });
131→    editorDispatch({ type: 'SET_VIEW_MODE', viewMode: 'plan' });
132→    if (roofSystem) {
133→      editorDispatch({ type: 'SELECT_OBJECT', id: roofSystem.id, objectType: 'roofSystem' });
134→      return;
135→    }
136→    editorDispatch({ type: 'DESELECT' });
137→  };
138→
139→  const selectTrussObject = (id, type, floorId = null) => {
140→    editorDispatch({ type: 'SET_MODEL_TARGET', modelTarget: 'truss' });
141→    if (floorId) {
142→      editorDispatch({ type: 'SET_ACTIVE_FLOOR', floorId });
143→    }
144→    editorDispatch({ type: 'SELECT_OBJECT', id, objectType: type });
145→  };
146→
147→  const setActiveFloor = (floorId) => {
148→    editorDispatch({ type: 'SET_ACTIVE_FLOOR', floorId });
149→  };
150→
151→  const addFloor = () => {
152→    const nextFloor = createFloorAboveHighest(project.floors || []);
153→    dispatch({ type: 'FLOOR_ADD', floor: nextFloor });
154→    selectFloor(nextFloor.id);
155→  };
156→
157→  const handleDuplicateFloor = (floorToDuplicate) => {
158→    const duplicatedFloor = duplicateFloor(floorToDuplicate.id);
159→    if (!duplicatedFloor) return;
160→
161→    dispatch({ type: 'FLOOR_DUPLICATE', floor: duplicatedFloor });
162→    selectFloor(duplicatedFloor.id);
163→  };
164→
165→  const handleDeleteFloor = (floorToDelete) => {
166→    if ((project.floors || []).length <= 1) return;
167→
168→    const confirmed = window.confirm(`Delete "${floorToDelete.name}"?`);
169→    if (!confirmed) return;
170→
171→    const remainingFloors = orderedFloors.filter((entry) => entry.id !== floorToDelete.id);
172→    const fallbackFloor = remainingFloors[0] || null;
173→
174→    dispatch({
175→      type: 'FLOOR_DELETE',
176→      floorId: floorToDelete.id,
177→      fallbackFloorId: fallbackFloor?.id ?? null,
178→    });
179→
180→    if (floorToDelete.id === activeFloorId && fallbackFloor) {
181→      if (workspaceMode === 'model') {
182→        selectFloor(fallbackFloor.id);
183→      } else {
184→        setActiveFloor(fallbackFloor.id);
185→      }
186→    }
187→  };
188→
189→  const addPhase = () => {
190→    const nextOrder = getNextPhaseOrder(project.phases || []);
191→    const color = PHASE_COLORS[nextOrder % PHASE_COLORS.length];
192→    const phase = createPhase(`Phase ${nextOrder + 1}`, nextOrder, color);
193→    dispatch({ type: 'PHASE_ADD', phase });
194→    editorDispatch({ type: 'SET_ACTIVE_PHASE', phaseId: phase.id });
195→    editorDispatch({ type: 'SELECT_OBJECT', id: phase.id, objectType: 'phase' });
196→  };
197→
