 43→  const handleOpenFile = async () => {
 44→    try {
 45→      const result = await openSketchProjectFile();
 46→      dispatch({ type: 'SKETCH_LOAD', project: result.project });
 47→      setFileHandle(result.fileHandle || null);
 48→      onClose();
 49→    } catch (err) {
 50→      if (!isFilePickerAbortError(err)) {
 51→        console.error('Failed to open sketch file:', err);
 52→      }
 53→    }
 54→  };
 55→
 56→  const handleImportFile = async (e) => {
 57→    const file = e.target.files?.[0];
 58→    if (!file) return;
 59→    try {
 60→      const result = await importSketchProjectFile(file);
 61→      dispatch({ type: 'SKETCH_LOAD', project: result.project });
 62→      setFileHandle(null);
 63→      onClose();
 64→    } catch (err) {
 65→      console.error('Failed to import sketch file:', err);
 66→    } finally {
 67→      e.target.value = '';
